DROP TABLE IF EXISTS `classroom`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `classroom` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(50) NOT NULL COMMENT '教室名称(如A101)',
  `building` varchar(50) DEFAULT NULL COMMENT '所在教学楼',
  `capacity` int NOT NULL DEFAULT '60' COMMENT '容纳人数',
  `type` varchar(20) NOT NULL DEFAULT 'lecture' COMMENT '类型: lecture-普通教室 lab-实验室 multimedia-多媒体',
  `facilities` varchar(255) DEFAULT NULL COMMENT '设施描述(投影仪,空调等)',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态: 0-停用 1-启用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='教室表';
/*!40101 SET character_set_client = @saved_cs_client */;

