DROP TABLE IF EXISTS `course`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `course` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `code` varchar(30) NOT NULL COMMENT '课程编号',
  `name` varchar(100) NOT NULL COMMENT '课程名称',
  `teacher_id` bigint NOT NULL COMMENT '授课教师ID',
  `credit` decimal(3,1) NOT NULL DEFAULT '0.0' COMMENT '学分',
  `hours` int NOT NULL DEFAULT '0' COMMENT '学时',
  `semester` varchar(20) NOT NULL COMMENT '学期(如2025-2026-1)',
  `weekday` int NOT NULL COMMENT '星期几(1-7)',
  `start_section` int NOT NULL COMMENT '开始节次(1-12)',
  `end_section` int NOT NULL COMMENT '结束节次(1-12)',
  `location` varchar(100) DEFAULT NULL COMMENT '上课地点',
  `max_students` int NOT NULL DEFAULT '100' COMMENT '最大选课人数',
  `current_count` int NOT NULL DEFAULT '0' COMMENT '当前已选人数',
  `version` int NOT NULL DEFAULT '0' COMMENT '乐观锁版本号',
  `description` text COMMENT '课程描述',
  `course_type` varchar(20) NOT NULL DEFAULT 'required' COMMENT '课程类型: required=必修, elective=选修',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态: 0-停用 1-启用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_code` (`code`),
  KEY `idx_teacher_id` (`teacher_id`),
  KEY `idx_semester` (`semester`),
  KEY `idx_weekday_section` (`weekday`,`start_section`,`end_section`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='课程表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `course` WRITE;
