DROP TABLE IF EXISTS `notice`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notice` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title` varchar(200) NOT NULL COMMENT '标题',
  `content` text NOT NULL COMMENT '内容',
  `publisher_id` bigint NOT NULL COMMENT '发布人ID',
  `category` varchar(30) NOT NULL DEFAULT 'general' COMMENT '分类: academic/activity/urgent/general',
  `target_role` varchar(50) DEFAULT 'all' COMMENT '目标角色: all/student/teacher',
  `is_top` int NOT NULL DEFAULT '0' COMMENT '是否置顶: 0-否 1-是',
  `publish_time` datetime DEFAULT NULL COMMENT '定时发布时间',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态: 0-草稿 1-已发布 2-已下架',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`),
  KEY `idx_publisher_id` (`publisher_id`),
  KEY `idx_category_status` (`category`,`status`),
  KEY `idx_publish_time` (`publish_time`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='通知公告表';
