INSERT INTO `notice` VALUES (1,'2025-2026学年第一学期选课通知','各位同学：\n第一学期选课将于9月1日开始，请登录系统完成选课。选课分三轮进行，具体安排请查看教务处网站。',1,'academic','student',1,'2025-08-25 09:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(2,'国庆节放假通知','根据学校安排，10月1日至7日放假调休，10月8日正常上课。请各位师生注意安全。',1,'general','all',1,'2025-09-25 10:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(3,'校园招聘会通知','2025年秋季校园招聘会将于10月15日在体育馆举行，参会企业200余家，请同学们提前准备简历。',2,'activity','student',0,'2025-09-28 14:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(4,'教务系统升级维护公告','教务系统将于本周六0:00-6:00进行升级维护，届时系统暂停服务，请提前做好安排。',1,'urgent','all',0,'2025-10-10 16:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(5,'教师节表彰大会通知','2025年教师节表彰大会将于9月10日下午2点在学术报告厅举行，欢迎全体教师参加。',2,'activity','teacher',0,'2025-09-05 08:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(6,'期末考试安排通知','2025-2026学年第一学期期末考试将于2026年1月6日-17日进行，具体安排请查看考试系统。',1,'academic','student',0,'2025-12-01 09:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(7,'实验室安全培训通知','所有使用实验室的师生必须参加安全培训，培训时间为10月20日下午2点，地点C实验楼201。',2,'urgent','all',0,'2025-10-15 10:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(8,'英语四六级考试报名通知','2025年12月英语四六级考试报名已开始，截止日期11月5日，请同学们及时报名。',2,'academic','student',0,'2025-10-20 09:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(9,'新学期教师培训通知','2025-2026学年第二学期教师培训将于2月20日-21日进行，请全体教师准时参加。',1,'academic','teacher',0,'2026-01-15 10:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(10,'校园网络故障紧急通知','因光缆施工，校园网将于今晚22:00-次日6:00中断，请提前保存工作。',1,'urgent','all',0,'2026-03-10 18:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(11,'春季运动会报名通知','第35届春季运动会将于4月20日举行，请各班级于4月5日前完成报名。',2,'activity','student',0,'2026-03-15 09:00:00',1,'2026-04-22 00:45:52','2026-04-22 00:45:52',0),(12,'草稿通知-未发布','此通知为草稿状态，不应被普通用户看到。',1,'general','all',0,NULL,0,'2026-04-22 00:45:52','2026-04-22 00:45:52',0);
