CREATE TABLE `repair` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '报修人ID',
  `title` varchar(200) NOT NULL COMMENT '报修标题',
  `content` text NOT NULL COMMENT '报修描述',
  `location` varchar(200) NOT NULL COMMENT '故障地点',
  `category` varchar(30) NOT NULL COMMENT '分类: electrical/plumbing/furniture/network/other',
  `urgency` varchar(10) NOT NULL DEFAULT 'normal' COMMENT '紧急程度: low/normal/high',
  `status` int NOT NULL DEFAULT '0' COMMENT '状态: 0-待处理 1-处理中 2-已完成 3-已关闭',
  `handler_id` bigint DEFAULT NULL COMMENT '处理人ID',
  `handle_result` text COMMENT '处理结果',
  `handle_time` datetime DEFAULT NULL COMMENT '处理时间',
  `rating` int DEFAULT NULL COMMENT '评价: 1-5星',
  `rating_content` varchar(500) DEFAULT NULL COMMENT '评价内容',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_handler_id` (`handler_id`),
  KEY `idx_category_status` (`category`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='报修工单表';
