CREATE TABLE `sys_user` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `username` varchar(50) NOT NULL COMMENT '用户名',
  `password` varchar(100) NOT NULL COMMENT '密码',
  `real_name` varchar(50) NOT NULL COMMENT '真实姓名',
  `id_card` varchar(100) DEFAULT NULL COMMENT '身份证号(加密存储)',
  `user_no` varchar(50) DEFAULT NULL COMMENT '用户编号(学号/工号)',
  `college` varchar(100) DEFAULT NULL COMMENT '学院',
  `major` varchar(100) DEFAULT NULL COMMENT '专业',
  `class_name` varchar(50) DEFAULT NULL COMMENT '班级',
  `first_login` int NOT NULL DEFAULT '1' COMMENT '是否首次登录: 0-否 1-是',
  `role` varchar(20) NOT NULL DEFAULT 'student' COMMENT '角色: admin/teacher/student',
  `phone` varchar(20) DEFAULT NULL COMMENT '手机号',
  `email` varchar(100) DEFAULT NULL COMMENT '邮箱',
  `avatar` varchar(255) DEFAULT NULL COMMENT '头像URL',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态: 0-禁用 1-启用',
